import sys
def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it)); M=int(next(it))
        items=[int(next(it)) for _ in range(N)]
        items.sort(reverse=True)
        bins=[]
        for sz in items:
            placed=False
            for i in range(len(bins)):
                if bins[i]>=sz:
                    bins[i]-=sz
                    placed=True
                    break
            if not placed:
                bins.append(M-sz)
        out.append(str(len(bins)))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

